mapper.select:
SELECT * FROM activities
WHERE review_status = 'approved'
  AND activity_status = 'open'

  AND organizer_user_id = #{organizerUserId}


  AND category = #{category}


  AND (title LIKE #{keyword} OR description LIKE #{keyword})


  AND area_code = #{areaCode}


  AND DATE(start_at) = CURRENT_DATE()


  AND start_at < DATE_ADD(CURRENT_DATE(), INTERVAL 7 DAY)


  AND participant_count < capacity

ORDER BY start_at ASC, updated_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT a.*, u.nickname AS applicant_nickname, u.avatar_url AS applicant_avatar_url
FROM applications a
INNER JOIN users u ON a.applicant_user_id = u.id
WHERE a.applicant_user_id = #{userId}

  AND a.status = #{status}

ORDER BY a.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT a.*, u.nickname AS applicant_nickname, u.avatar_url AS applicant_avatar_url
FROM applications a
INNER JOIN activities ac ON a.activity_id = ac.id
INNER JOIN users u ON a.applicant_user_id = u.id
WHERE ac.organizer_user_id = #{userId}

  AND a.status = #{status}

ORDER BY a.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM applications
WHERE activity_id = #{activityId}
  AND applicant_user_id = #{userId}
  AND status IN ('pending', 'accepted_pending_payment', 'accepted_paid')

SELECT COALESCE(MAX(attempt_no), 0) + 1
FROM applications
WHERE activity_id = #{activityId}
  AND applicant_user_id = #{userId}

